(function initLocalMsgReader(global){
  if (!global || typeof global.MSGReader === 'function') return;

  function toUint8Array(input){
    if (input instanceof Uint8Array) return input;
    if (input instanceof ArrayBuffer) return new Uint8Array(input);
    if (ArrayBuffer.isView(input) && input.buffer) return new Uint8Array(input.buffer);
    return new Uint8Array(0);
  }

  function normalize(text){
    return String(text || '')
      .replace(/\r\n?/g, '\n')
      .replace(/[\t\f\v ]+/g, ' ')
      .replace(/\n{3,}/g, '\n\n')
      .trim();
  }

  function extractSegments(bytes){
    var utf16 = new TextDecoder('utf-16le', { fatal: false }).decode(bytes)
      .split(/\u0000+/)
      .map(normalize)
      .filter(function(chunk){ return chunk.length > 6 && /[A-Za-z]/.test(chunk); });
    var latin = new TextDecoder('latin1', { fatal: false }).decode(bytes)
      .split(/\u0000|[\x01-\x08\x0B\x0C\x0E-\x1F]+/g)
      .map(normalize)
      .filter(function(chunk){ return chunk.length > 6 && /[A-Za-z]/.test(chunk); });
    var seen = Object.create(null);
    return utf16.concat(latin).filter(function(segment){
      if (seen[segment]) return false;
      seen[segment] = true;
      return true;
    });
  }

  function pickHeader(segments, label){
    var pattern = new RegExp('^' + label + '\\s*:\\s*(.+)$', 'i');
    for (var i = 0; i < segments.length; i += 1) {
      var lines = segments[i].split('\n');
      for (var j = 0; j < lines.length; j += 1) {
        var match = pattern.exec(lines[j].trim());
        if (match && match[1]) return match[1].trim();
      }
    }
    return '';
  }

  function pickBody(segments){
    var sorted = segments.slice().sort(function(a, b){ return b.length - a.length; });
    for (var i = 0; i < sorted.length; i += 1) {
      var segment = sorted[i];
      var words = segment.split(/\s+/).filter(Boolean).length;
      if (words >= 20) return segment;
    }
    return sorted[0] || '';
  }

  function LocalMSGReader(input){
    this._bytes = toUint8Array(input);
  }

  LocalMSGReader.prototype.getFileData = function(){
    if (!this._bytes || this._bytes.length < 32) throw new Error('Not enough bytes to parse .msg content');
    var segments = extractSegments(this._bytes);
    if (!segments.length) throw new Error('No readable .msg segments found');
    return {
      subject: pickHeader(segments, 'Subject'),
      senderName: pickHeader(segments, 'From'),
      recipients: pickHeader(segments, 'To'),
      cc: pickHeader(segments, 'Cc'),
      date: pickHeader(segments, 'Date') || pickHeader(segments, 'Sent'),
      body: pickBody(segments)
    };
  };

  global.MSGReader = LocalMSGReader;
})(window);
